`getEmails` accepts a `filter` string that is inserted directly into EWS XML. While the filter values are validated in practice, a future developer might extend the filter parser to accept more filter types without proper validation.

## Recommended Fix

Replace the `includes()`-based filter parsing with a proper structured filter builder:

```typescript
interface EmailFilter {
  isRead?: boolean;
  flagStatus?: 'Flagged' | 'NotFlagged' | 'Complete';
  importance?: 'Low' | 'Normal' | 'High';
  from?: string;
  to?: string;
}

function buildRestrictionXml(filter: EmailFilter): string {
  const restrictions: string[] = [];

  if (filter.isRead !== undefined) {
    restrictions.push(`<t:IsEqualTo>
      <t:FieldURI FieldURI="message:IsRead"/>
      <t:FieldURIOrConstant><t:Constant Value="${filter.isRead ? 'false' : 'true'}"/></t:FieldURIOrConstant>
    </t:IsEqualTo>`);
  }

  if (restrictions.length === 0) return '';
  if (restrictions.length === 1) return `<m:Restriction>${restrictions[0]}</m:Restriction>`;
  return `<m:Restriction><t:And>${restrictions.join('')}</t:And></m:Restriction>`;
}
